          {/* ── Follow-Up Reminders ── */}
          {mounted && followUps.length > 0 && (
            <div className="bg-white dark:bg-dark-panel rounded-xl shadow-sm border border-gray-200 dark:border-dark-border p-4 md:p-5 mb-4 md:mb-6">
