                                {l.confirm_active}
                              </button>
                            </div>
                          )}
                        </div>
                      );
                    })
                  ) : (
                    allSearches.length === 0 ? (
                      <div className="p-8 text-center text-xs text-slate-400">{l.no_active}</div>
