                        value={tagInput.zone} 
                        onChange={e => {
                          const val = e.target.value;
                          setTagInput({...tagInput, zone: val});
                          setZoneSuggestions(val.length > 1 ? searchACMLocations(val, 10) : []);
                        }} 
                        onKeyDown={e => {
                          if (e.key === 'Enter') {
