  const typeLabel = (tp) => t('ofc_lead_' + ({propiedad_especifica:'propiedad',comprar:'comprar',vender:'vender',alquiler:'alquiler',otro:'otro'}[tp]||'otro'));
  const statusLabel = (s) => {
